mapper.select:
SELECT p.id, p.user_id, p.category_id, p.title, p.content, p.images, p.view_count, p.support_count, p.comment_count, p.is_top, p.create_time, u.nick_name, u.avatar, u.sex FROM osh_bbs_post p LEFT JOIN sys_user u ON p.user_id = u.user_id WHERE p.is_delete = 0 AND p.id = #{id}
AND p.category_id = #{categoryId}
AND p.is_top = #{isTop}
ORDER BY p.is_top DESC, p.create_time DESC

mapper.update:
UPDATE osh_bbs_post
SET support_count = support_count + 1
WHERE id = #{postId}

UPDATE osh_bbs_post
SET support_count = GREATEST(support_count - 1, 0)
WHERE id = #{postId}

UPDATE osh_bbs_post
SET comment_count = comment_count + 1
WHERE id = #{postId}
